mapper.select:
SELECT id, user_id, sport_id, content, status, checkin_time, reviewer_id, review_time
FROM checkin_record
WHERE id = #{id}

SELECT r.id, r.user_id, r.sport_id, s.name AS sport_name, r.content, r.status, r.checkin_time, r.reviewer_id, r.review_time FROM checkin_record r JOIN sport s ON r.sport_id = s.id WHERE r.user_id = #{userId}
AND r.status = #{status}
ORDER BY r.checkin_time DESC

SELECT r.id, r.user_id, u.username, u.nickname, r.sport_id, s.name AS sport_name, r.content, r.status, r.checkin_time, r.reviewer_id, rv.nickname AS reviewer_nickname, r.review_time FROM checkin_record r JOIN user u ON r.user_id = u.id JOIN sport s ON r.sport_id = s.id LEFT JOIN user rv ON r.reviewer_id = rv.id
r.status = #{status}
ORDER BY r.checkin_time DESC

mapper.update:
UPDATE checkin_record
SET status = #{status},
    reviewer_id = #{reviewerId},
    review_time = #{reviewTime}
WHERE id = #{id}
